+            attacker_action: ActionId("atk".into()),
+            defender_action: ActionId("def".into()),
+            dimension: LossDimension::PerformanceCost,
+            loss_millionths: 200_000,
+        },
+        LossEntry {
+            attacker_action: ActionId("atk".into()),
+            defender_action: ActionId("def".into()),
+            dimension: LossDimension::AvailabilityCost,
+            loss_millionths: 100_000,
+        },
