+            &ActionId("atk-1".into()),
+            &ActionId("def-2".into()),
+            LossDimension::PerformanceCost
+        ),
+        Some(50_000)
+    );
+    // wrong dimension → None
+    assert!(
+        tensor
+            .lookup(
+                &ActionId("atk-1".into()),
+                &ActionId("def-1".into()),
+                LossDimension::AvailabilityCost
